const testSummary = { North: 5, East: 3, South: 4, West: 2 };

const spy = __helpers.spyOn(console, "log");
try {
  printSummary(testSummary);
  const expectedCall = ["\nThroughput Summary"];
  assert.deepEqual(
    spy.calls[0],
    expectedCall,
    "printSummary should log the throughput summary header"
  );
} catch (err) {
  assert.fail(err);
} finally {
  spy.restore();
}
